            s.enqueue_outbound_pcm(&vec![0; 100], true);
            let (b64, done) = s.poll_outbound();
            assert!(!b64.is_empty());
            assert!(done);
            // Second poll: no audio, no `done` (we already consumed it).
            let (b64, done) = s.poll_outbound();
            assert!(b64.is_empty());
            assert!(!done);
        }).unwrap

